{
  "plan": [
    {
      "tool": "iam.check_permission",
      "arguments": {
        "user": "provisioning_workflow",
        "resource": "iam.roles",
        "action": "write"
      },
      "depends_on": []
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "workflow_approvals",
        "filter": {
          "status": "approved",
          "type": "access_provisioning"
        }
      },
      "depends_on": [1]
    },
    {
      "tool": "sql.snowflake.query",
      "arguments": {
        "query": "SELECT DISTINCT user_id, permission, resource, action, result, access_time FROM access_log_facts WHERE user_id IS NOT NULL ORDER BY access_time DESC LIMIT 100"
      },
      "depends_on": [1]
    },
    {
      "tool": "iam.check_permission",
      "arguments": {
        "user": "$2.results.requested_user",
        "resource": "iam.roles",
        "action": "read"
      },
      "depends_on": [2, 3]
    },
    {
      "tool": "iam.grant_role",
      "arguments": {
        "user": "$2.results.requested_user",
        "role": "$2.results.requested_role",
        "approved_by": "$2.results.manager_id",
        "approval_reference": "$2.results.approval_id"
      },
      "depends_on": [1, 2, 4]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "iam.grant_role",
        "performed_by": "provisioning_workflow",
        "target_user": "$2.results.requested_user",
        "role_granted": "$2.results.requested_role",
        "approval_id": "$2.results.approval_id",
        "manager_id": "$2.results.manager_id",
        "prior_role_state": "$3.results",
        "timestamp": "now"
      },
      "depends_on": [5]
    },
    {
      "tool": "mongo.update",
      "arguments": {
        "collection": "workflow_approvals",
        "filter": {
          "_id": "$2.results.approval_id"
        },
        "update": {
          "$set": {
            "status": "completed",
            "completed_at": "now",
            "audit_log_id": "$6.log_id"
          }
        }
      },
      "depends_on": [6]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "workflow_approval.status_updated",
        "performed_by": "provisioning_workflow",
        "approval_id": "$2.results.approval_id",
        "new_status": "completed",
        "audit_log_id": "$6.log_id",
        "timestamp": "now"
      },
      "depends_on": [7]
    },
